UPDATE catalog_product_entity_text
SET value = '<h3 class="course-topic-h3">Topic 1 Network Fundamentals</h3>
<ul>
<li>Explain the role and function of network components</li>
<li>Describe characteristics of network topology architectures</li>
<li>Compare physical interface and cabling types</li>
<li>Identify interface and cable issues (collisions, errors, mismatch duplex, and/or speed)</li>
<li>Compare TCP to UDP</li>
